    "admin.media.settings.title": { "ko": "저장소 유형 선택", "en": "Select Storage Type", "ja": "ストレージタイプの選択" },
    "admin.media.settings.desc": { "ko": "이미지 파일을 저장할 저장소를 선택하세요. 변경 후 저장하면 즉시 적용됩니다.", "en": "Select the storage for your image files. Changes take effect immediately after saving.", "ja": "画像ファイルを保存するストレージを選択してください。変更を保存すると即座に適用されます。" },
    "admin.media.settings.r2_desc": { "ko": "공식 권장 저장소. 무료 티어 제공, 목록 조회/삭제 모두 지원.", "en": "Official recommended storage. Free tier available, supports both listing and deletion.", "ja": "公式推奨ストレージ。無料枠があり、リスト表示・削除ともに対応しています。" },
    "admin.media.settings.kv_desc": { "ko": "업로드/삭제 지원. 파일 목록 조회는 API 비용 문제로 비활성화.", "en": "Supports upload/delete. File listing disabled due to API cost considerations.", "ja": "アップロード・削除に対応。ファイルリスト表示はAPIコストの関係で無効化されています。" },
    "admin.media.settings.supabase_desc": { "ko": "Supabase 프로젝트의 Storage 버킷 사용. URL과 서비스 키 필요.", "en": "Use Supabase Project Storage bucket. Requires URL and Service Key.", "ja": "Supabase プロジェクトの Storage バケットを使用します。URL とサービスキーが必要です。" },
    "admin.media.settings.imagekit_desc": { "ko": "외부 CDN 서비스. 이미지 최적화 및 변환 기능 제공.", "en": "External CDN service. Provides image optimization and transformation.", "ja": "外部CDNサービス。画像の最適化や変換機能を提供します。" },
    "admin.media.settings.save_btn": { "ko": "설정 저장", "en": "Save Settings", "ja": "設定を保存" },
    "admin.media.settings.saved": { "ko": "저장됨!", "en": "Saved!", "ja": "保存されました！" },
    "admin.media.settings.loading": { "ko": "설정 불러오는 중...", "en": "Loading settings...", "ja": "設定を読み込み中..." },
    "admin.media.supabase.title": { "ko": "Supabase Storage 설정", "en": "Supabase Storage Settings", "ja": "Supabase Storage 設定" },
    "admin.media.supabase.bucket_label": { "ko": "버킷 이름", "en": "Bucket Name", "ja": "バケット名" },
    "admin.media.supabase.bucket_hint": { "ko": "Supabase Storage에서 생성한 버킷 이름 (기본값: images)", "en": "Bucket name created in Supabase Storage (default: images)", "ja": "Supabase Storage で作成したバケット名 (デフォルト: images)" },
    "admin.media.imagekit.title": { "ko": "ImageKit 설정", "en": "ImageKit Settings", "ja": "ImageKit 設定" },
    "admin.media.imagekit.serving_type": { "ko": "이미지 서빙 방식", "en": "Image Serving Method", "ja": "画像配信方式" },
    "admin.media.imagekit.direct": { "ko": "🚀 CDN 직접 연결", "en": "🚀 Direct CDN Connection", "ja": "🚀 CDN 直接接続" },
    "admin.media.imagekit.direct_desc": { "ko": "최고 속도. 포스트에 ImageKit CDN URL이 저장됨.", "en": "Maximum speed. ImageKit CDN URL is stored in posts.", "ja": "最高速。投稿には ImageKit CDN の URL が保存されます。" },
    "admin.media.imagekit.proxy": { "ko": "🔗 도메인 프록시", "en": "🔗 Domain Proxy", "ja": "🔗 ドメインプロキシ" },
    "admin.media.imagekit.proxy_desc": { "ko": "myblog.com/images/ 주소로 서빙. 저장소 교체 시 포스트 URL 유지.", "en": "Served via myblog.com/images/. URL is maintained when switching storage.", "ja": "myblog.com/images/ のアドレスで配信。ストレージ交換時も投稿の URL を維持できます。" },
    "admin.media.kv.notice_title": { "ko": "KV 저장소 사용 시 주의사항", "en": "Precautions when using KV storage", "ja": "KV ストレージ使用時の注意事項" },
    "admin.media.kv.notice_desc": { "ko": "파일 업로드 및 삭제는 가능하지만, 파일 목록 조회(media 브라우저)는 비활성화됩니다. 파일 관리가 필요하다면 R2 또는 Supabase를 권장합니다.", "en": "Upload and delete are available, but file listing (media browser) is disabled. R2 or Supabase is recommended if file management is needed.", "ja": "ファイルのアップロードと削除は可能ですが、ファイルリスト表示 (メディアブラウザ) は無効になります。ファイル管理が必要な場合は、R2 または Supabase を推奨します。" },
    "admin.media.kv.notice_hint": { "ko": "또한 wrangler.toml에서 IMAGES_KV 명세 바인딩의 주석을 해제해야 합니다.", "en": "Also, the IMAGES_KV binding in wrangler.toml must be uncommented.", "ja": "また、wrangler.toml で IMAGES_KV バインディングのコメントを解除する必要があります。" },
    "admin.media.kv.banner_title": { "ko": "파일 목록을 지원하지 않는 저장소 모드입니다.", "en": "Storage mode does not support file listing.", "ja": "ファイルリストに非対応のストレージモードです。" },
    "admin.media.kv.banner_p1": { "ko": "현재 KV 저장소를 사용 중입니다. KV의 파일 목록 스캔(prefix scan)은 Cloudflare Workers API를 매번 호출하기 때문에, 무료 쿼터를 빠르게 소진할 수 있어 목록 조회를 비활성화했습니다.", "en": "Currently using KV storage. KV prefix scans call Cloudflare Workers API frequently, which can quickly consume the free quota, so listing is disabled.", "ja": "現在 KV ストレージを使用中です。KV のファイルリストスキャンは API を頻繁に呼び出すため、無料枠をすぐに使い果たす可能性があることから、リスト表示を無効にしています。" },
    "admin.media.kv.banner_p2": { "ko": "이미지 업로드 및 삭제는 정상적으로 이용 가능합니다. 파일 목록 관리가 필요하다면 설정에서 R2 또는 ImageKit으로 전환을 권장합니다.", "en": "Image upload and deletion are still available. For file management, switching to R2 or ImageKit is recommended.", "ja": "画像のアップロードと削除は正常に利用可能です。ファイル管理が必要な場合は、設定から R2 または ImageKit への切り替えを推奨します。" },
    "admin.media.danger.title": { "ko": "모든 미디어 파일 삭제", "en": "Purge All Media Files", "ja": "すべてのメディアファイルを削除" },
    "admin.media.danger.desc": { "ko": "이 작업은 되돌릴 수 없습니다. R2 버킷에 있는 모든 파일이 영구적으로 삭제됩니다. 테스트 환경이나 초기화가 필요한 경우에만 사용하세요.", "en": "This action is irreversible. All files in the R2 bucket will be permanently deleted. Use only for test environments or initialization.", "ja": "この操作は取り消せません。バケット内のすべてのファイルが永久に削除されます。テスト環境や初期化が必要な場合にのみ使用してください。" },
