    "admin.backup.info": { "ko": "포스트, 카테고리, 태그 데이터와 미디어 파일을 관리합니다.", "en": "Manage post, category, tag data and media files.", "ja": "投稿、カテゴリ、タグデータ、およびメディアファイルを管理します。" },
    "admin.backup.theme_editor_link": { "ko": "디자인(테마/레이아웃) 백업은 디자인 에디터 > 설정/관리에서 별도로 관리하세요.", "en": "Manage design (theme/layout) backups separately in Design Editor > Settings/Management.", "ja": "デザイン（テーマ/レイアウト）のバックアップは、デザインエディタ > 設定/管理で別途管理してください。" },
