    "admin.backup.import_hint": { "ko": "백업된 JSON 파일을 선택하여 데이터를 복원합니다.", "en": "Select a backed-up JSON file to restore data.", "ja": "バックアップされた JSON ファイルを選択してデータを復元します。" },
    "admin.backup.import_warning": { "ko": "⚠️ 경고: 복원 시 현재 모든 데이터가 삭제되고 백업 파일로 대체됩니다.", "en": "⚠️ Warning: Restoring will delete all current data and replace it with the backup file.", "ja": "⚠️ 警告：復元すると現在のすべてのデータが削除され、バックアップファイルに置き換えられます。" },
