    "admin.backup.full_title": { "ko": "🛡️ 전체 시스템 백업 및 복원", "en": "🛡️ Full System Backup & Restore", "ja": "🛡️ 全システムバックアップと復元" },
    "admin.backup.full_warning_title": { "ko": "매우 중요: 사이트 전체 복구 전용", "en": "Extremely Important: For Full Site Recovery Only", "ja": "非常に重要：サイト全体の復元専用" },
    "admin.backup.full_warning_desc": { "ko": "이 기능은 DB의 모든 설정, 콘텐츠, 보안 키를 포함한 '전체 상태'를 백업하고 복구합니다. 복원 시 현재 사이트의 모든 정보가 삭제되며, 타인의 백업 파일 사용 시 보안 위험이 있으므로 반드시 본인의 백업 파일만 사용하세요.", "en": "This feature backs up and restores the 'full state' including all settings, content, and security keys. Restoring will delete all current information. Using someone else's backup file poses a security risk; only use your own backup files.", "ja": "この機能は、すべての設定、コンテンツ、セキュリティキーを含む「完全な状態」をバックアップおよび復元します。復元すると、現在のサイトのすべての情報が削除されます。他人のバックアップファイルを使用するとセキュリティ上のリスクがあるため、必ず自分のバックアップファイルのみを使用してください。" },
    "admin.backup.full_export": { "ko": "시스템 전체 데이터 내보내기", "en": "Export Full System Data", "ja": "システム全データの書き出し" },
    "admin.backup.full_export_desc": { "ko": "DB의 모든 테이블과 환경 설정을 JSON으로 추출", "en": "Extract all DB tables and environment settings to JSON", "ja": "すべての DB テーブルと環境設定を JSON として抽出" },
    "admin.backup.full_import": { "ko": "시스템 전체 데이터 복원", "en": "Restore Full System Data", "ja": "システム全データの復元" },
    "admin.backup.full_import_desc": { "ko": "백업 파일을 사용하여 사이트를 이전 상태로 완전 복구", "en": "Complete site recovery to a previous state using a backup file", "ja": "バックアップファイルを使用してサイトを以前の状態に完全復旧" },
    "admin.backup.full_confirm": { "ko": "⚠️ [위험] 사이트의 모든 설정과 콘텐츠가 백업 파일로 대체됩니다. 이 작업은 되돌릴 수 없습니다. 계속하시겠습니까?", "en": "⚠️ [DANGER] All site settings and content will be replaced by the backup file. This action cannot be undone. Continue?", "ja": "⚠️ [危険] サイトのすべての設定とコンテンツがバックアップファイルに置き換えられます。この操作は取り消せません。続行しますか？" },
