    "blog.profile.logout": { "ko": "로그아웃", "en": "Log Out", "ja": "ログアウト" },
    "blog.profile.danger_title": { "ko": "Danger Zone (회원 탈퇴)", "en": "Danger Zone (Delete Account)", "ja": "Danger Zone (会員退会)" },
    "blog.profile.danger_desc": { "ko": "탈퇴 시 작성한 댓글과 방명록을 제외한 모든 개인 정보가 즉시 파기되며 복구할 수 없습니다.", "en": "Upon withdrawal, all personal information except comments and guestbook posts will be permanently deleted and cannot be recovered.", "ja": "退会すると、作成したコメントやゲストブックを除くすべての個人情報が直ちに破棄され、復旧できません。" },
    "blog.profile.withdraw_btn": { "ko": "회원 탈퇴 및 정보 파기", "en": "Withdraw & Delete Data", "ja": "退会および情報破棄" },
    "blog.profile.withdraw_confirm_title": { "ko": "정말 회원 탈퇴를 진행하시겠습니까?", "en": "Are you sure you want to delete your account?", "ja": "本当に退会手続きを進行しますか？" },
    "blog.profile.withdraw_confirm_desc": { "ko": "아래의 중요한 탈퇴 안내 정책을 꼭 읽어주세요.", "en": "Please read the important account deletion policies below.", "ja": "以下の重要な退会案内ポリシーを必ずお読みください。" },
    "blog.profile.withdraw_policy_title": { "ko": "⚠️ 회원 탈퇴 중요 안내 및 정책", "en": "⚠️ Important Account Deletion Notice & Policy", "ja": "⚠️ 会員退会の重要なご案内およびポリシー" },
    "blog.profile.policy_item1": { "ko": "회원 탈퇴 진행 시, 모든 계정 정보가 안전하게 영구 파기되며 즉시 로그아웃됩니다.", "en": "Upon account deletion, all account information is safely and permanently destroyed, and you will be logged out immediately.", "ja": "退会手続きの進行時、すべてのアカウント情報は安全に永久破棄され、直ちにログアウトされます。" },
    "blog.profile.policy_item2": { "ko": "작성하신 댓글 및 방명록 글은 서비스 무결성을 위해 탈퇴 후에도 보존됩니다.", "en": "To maintain service integrity, your comments and guestbook posts will be preserved even after deletion.", "ja": "作成されたコメントおよびゲストブックの投稿は、サービスの整合性維持のために退会後も保存されます。" },
    "blog.profile.policy_item3": { "ko": "작성하신 게시물 중 삭제를 원하는 내용이 있으시다면 반드시 탈퇴 전에 직접 삭제해 주시기 바랍니다.", "en": "If you wish to delete any of your written posts, please make sure to delete them yourself before deleting your account.", "ja": "作成された投稿のうち削除を希望するものがある場合は、必ず退会前にご自身で削除してください。" },
    "blog.profile.withdraw_agree": { "ko": "위 안내 사항 및 댓글 보존 정책을 모두 숙지하였으며, 탈퇴 진행에 확실히 동의합니다.", "en": "I have read and understood all the notices and comment preservation policies above, and I fully agree to delete my account.", "ja": "上記のご案内およびコメント保存ポリシーをすべて理解し、退会の進行に確実に同意します。" },
